function $(id){return document.getElementById(id)}
function toggleMenu(){const n=$('navlinks'); if(n) n.classList.toggle('open')}
function download(filename, text, type='text/plain'){const blob=new Blob([text],{type}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=filename; document.body.appendChild(a); a.click(); a.remove(); setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function toCSV(rows){const cols=Object.keys(rows[0]||{}); const esc=v=>'"'+String(v??'').replaceAll('"','""')+'"'; return cols.join(',')+'\n'+rows.map(r=>cols.map(c=>esc(r[c])).join(',')).join('\n')}
function initRiskTable(){const tbody=$('riskBody'); if(!tbody) return; const search=$('riskSearch'), cat=$('riskCategory'), impact=$('riskImpact'); const cats=[...new Set(LR360_RISKS.map(r=>r.category))]; if(cat && cat.options.length<2) cats.forEach(c=>cat.insertAdjacentHTML('beforeend',`<option>${c}</option>`)); function render(){let q=(search?.value||'').toLowerCase(); let c=cat?.value||''; let i=impact?.value||''; let rows=LR360_RISKS.filter(r=>(!q||JSON.stringify(r).toLowerCase().includes(q))&&(!c||r.category===c)&&(!i||r.impact===i)); tbody.innerHTML=rows.map(r=>`<tr><td><strong>${r.title}</strong><br><span class="small">${r.description}</span></td><td>${r.group}<br><span class="small">${r.category}</span></td><td><span class="status ${r.likelihood}">${r.likelihood}</span></td><td><span class="status ${r.impact}">${r.impact}</span></td><td>${r.mitigation}</td><td>${r.owner}</td></tr>`).join(''); const count=$('riskCount'); if(count) count.textContent=rows.length; } ['input','change'].forEach(ev=>{search?.addEventListener(ev,render);cat?.addEventListener(ev,render);impact?.addEventListener(ev,render)}); render()}
function initDashboard(){const area=$('dashArea'); if(!area) return; LR360_CATEGORIES.forEach(c=>area.insertAdjacentHTML('beforeend',`<option value="${c.id}">${c.name}</option>`)); const sliders=['awareness','exposure','support','readiness']; sliders.forEach(s=>{const el=$(s); const out=$(s+'Out'); if(el&&out){el.oninput=update; out.textContent=el.value;}}); area.onchange=update; const actions=$('mitigationActions'); let saved=JSON.parse(localStorage.getItem('lr360_actions')||'[]'); function actionRows(){if(!actions)return; actions.innerHTML=saved.map((a,idx)=>`<tr><td>${a.action}</td><td>${a.owner}</td><td>${a.due}</td><td>${a.status}</td><td><button class="btn dark" onclick="deleteAction(${idx})">Remove</button></td></tr>`).join('')||'<tr><td colspan="5">No actions added.</td></tr>'} window.deleteAction=(idx)=>{saved.splice(idx,1); localStorage.setItem('lr360_actions',JSON.stringify(saved)); actionRows()}; window.addAction=()=>{const actionField=$('actionText'), ownerField=$('actionOwner'), dueField=$('actionDue'); if(actionField && !actionField.value.trim()){actionField.reportValidity(); return;} if(ownerField && !ownerField.value.trim()){ownerField.reportValidity(); return;} if(dueField && !dueField.value){dueField.reportValidity(); return;} const a=actionField.value.trim(); saved.push({action:a,owner:ownerField.value||'Youth + Support Lead',due:dueField.value||'TBD',status:$('actionStatus').value||'Not Started'}); localStorage.setItem('lr360_actions',JSON.stringify(saved)); $('actionText').value=''; actionRows(); update();}; window.exportDashboard=()=>{const payload=buildReport(); if(payload) download('liferisk360-youth-dashboard-report.html',payload,'text/html')}; window.printReport=()=>window.print(); window.exportActionsJSON=()=>download('liferisk360-mitigation-actions.json',JSON.stringify(saved,null,2),'application/json'); function update(){sliders.forEach(s=>{const out=$(s+'Out'); if(out) out.textContent=$(s).value}); const awareness=+$('awareness').value, exposure=+$('exposure').value, support=+$('support').value, readiness=+$('readiness').value; const score=Math.round((awareness*0.3 + (100-exposure)*0.25 + support*0.2 + readiness*0.25)); $('overallScore').textContent=score; $('scoreBar').style.width=score+'%'; let label=score<40?'High Support Needed':score<65?'Developing Readiness':score<82?'Strong Progress':'Action Ready'; $('scoreLabel').textContent=label; const cat=LR360_CATEGORIES.find(c=>c.id===area.value)||LR360_CATEGORIES[0]; $('areaSummary').textContent=cat.summary; const related=LR360_RISKS.filter(r=>r.category===cat.name).slice(0,5); $('immediateActions').innerHTML=related.map(r=>`<li><strong>${r.title}:</strong> ${r.mitigation}</li>`).join(''); const bars=$('miniChart'); if(bars){bars.innerHTML=`<div style="height:${awareness}%"><span>Aware</span></div><div style="height:${exposure}%"><span>Exposure</span></div><div style="height:${support}%"><span>Support</span></div><div style="height:${readiness}%"><span>Ready</span></div>`} $('reportPreview').innerHTML = `<h3>Readiness Summary</h3><p><strong>Selected Area:</strong> ${cat.name}</p><p><strong>Overall Score:</strong> ${score} / 100 - ${label}</p><p><strong>Recommended Focus:</strong> ${related[0]?.mitigation||'Continue strengthening goals and support.'}</p><p><strong>Mitigation Actions:</strong> ${saved.length} action(s) tracked.</p>`; } function buildReport(){for(const id of ['reportName','reportEmail','reportPhone','reportAgeGroup']){const el=$(id); if(el && !el.value){el.reportValidity(); return ''}} const name=($('reportName')?.value||'Participant').trim(); const email=($('reportEmail')?.value||'Not provided').trim(); const phone=($('reportPhone')?.value||'Not provided').trim(); const ageGroup=($('reportAgeGroup')?.value||'Not provided').trim(); return `<!doctype html><html><head><meta charset="utf-8"><title>LifeRisk360 Report</title><link rel="stylesheet" href="/wp-content/uploads/liferisk360/assets/style.css"></head><body><main class="wrap section"><h1>LifeRisk360 Youth Readiness Report</h1><p><strong>Name:</strong> ${name}</p><p><strong>Email:</strong> ${email}</p><p><strong>Phone:</strong> ${phone}</p><p><strong>Age Group:</strong> ${ageGroup}</p>${$('reportPreview').innerHTML}<h2>Mitigation Actions</h2><table><thead><tr><th>Action</th><th>Owner</th><th>Due</th><th>Status</th></tr></thead><tbody>${saved.map(a=>`<tr><td>${a.action}</td><td>${a.owner}</td><td>${a.due}</td><td>${a.status}</td></tr>`).join('')}</tbody></table><div class="supporting-notes"><h2>Supporting Notes</h2><ul><li>This report is intended for awareness, prevention, planning, and structured conversation.</li><li>Scores should be reviewed together with context, age, support environment, and the selected risk group.</li><li>Recommended actions should be assigned to an appropriate youth, parent, guardian, school, mentor, or approved support person.</li><li>Where immediate safety concerns exist, use established emergency, school, guardian, or professional support channels.</li></ul></div><p class="small">Generated from the LifeRisk360 platform. This report is educational and not a crisis response tool.</p></main></body></html>`} actionRows(); update();}
function initForms(){document.querySelectorAll('form[data-store]').forEach(form=>{form.addEventListener('submit',e=>{e.preventDefault(); const data=Object.fromEntries(new FormData(form).entries()); data.createdAt=new Date().toISOString(); const key='lr360_'+form.dataset.store; const arr=JSON.parse(localStorage.getItem(key)||'[]'); arr.push(data); localStorage.setItem(key,JSON.stringify(arr)); const msg=form.querySelector('.form-message'); if(msg) msg.textContent='Saved locally. Export from this page or connect the form to your WordPress form plugin.'; form.reset();})})}
function exportStored(key){const arr=localStorage.getItem('lr360_'+key)||'[]'; download('liferisk360-'+key+'.json',arr,'application/json')}
function initLifePlan(){const form=$('lifePlanForm'); if(!form)return; const output=$('lifePlanOutput'); function buildStatement(data){return `My goal is to strengthen my ${data.education||'education'}, build ${data.skills||'useful skills'}, avoid ${data.risks||'harmful risks'}, and take the next step of ${data.action||'building disciplined weekly habits'}.`} function render(data){const statement=buildStatement(data); output.innerHTML=`<h3>My Life Direction Statement</h3><p>${statement}</p><div class="supporting-notes"><h4>Supporting Notes</h4><ul><li>Review this plan weekly and update the next action when progress is made.</li><li>Share the plan only with a trusted parent, guardian, teacher, mentor, or approved support person.</li><li>Use the dashboard to connect this plan to specific risk-awareness and readiness actions.</li></ul></div>`; return statement;} form.onsubmit=e=>{e.preventDefault(); if(!form.checkValidity()){form.reportValidity(); return;} const data=Object.fromEntries(new FormData(form).entries()); localStorage.setItem('lr360_lifeplan',JSON.stringify(data)); render(data)}; const saved=localStorage.getItem('lr360_lifeplan'); if(saved){const d=JSON.parse(saved); Object.entries(d).forEach(([k,v])=>{const el=form.elements[k]; if(el) el.value=v}); render(d);} const printBtn=$('printLifePlanBtn'); if(printBtn){printBtn.onclick=()=>{if(!form.checkValidity()){form.reportValidity(); return;} const data=Object.fromEntries(new FormData(form).entries()); render(data); window.print();};} const emailBtn=$('emailLifePlanBtn'); if(emailBtn){emailBtn.onclick=()=>{if(!form.checkValidity()){form.reportValidity(); return;} const data=Object.fromEntries(new FormData(form).entries()); const statement=render(data); const subject=encodeURIComponent('LifeRisk360 Life Direction Statement'); const body=encodeURIComponent(`LifeRisk360 Life Direction Statement\n\n${statement}\n\nSupporting notes:\n- Review this plan weekly.\n- Share it only with trusted support people.\n- Use the dashboard to connect this plan to risk-awareness actions.`); window.location.href=`mailto:?subject=${subject}&body=${body}`;};}}

function initGame(){
  const root=$('gameRoot');
  if(!root) return;
  const GROUPS={
    'Personal Safety':{icon:'🛡️',intro:'Practice decisions that protect your movement, boundaries, friendships, and trusted support.',metrics:['Safety Awareness','Boundary Choices','Trusted Support','Action Readiness'],scenes:[
      ['A friend wants you to go somewhere unfamiliar without telling anyone.','Pause, check the plan, and tell a trusted adult where you are going.','Ask more questions and suggest a safer public place.','Go quietly because you do not want to disappoint them.',[18,16,18,14],[-18,-18,-20,-16],'Use the 4-check rule: place, people, purpose, and way home.'],
      ['Someone keeps pressuring you after you already said no.','Repeat your boundary and move toward a safer person or place.','Buy time by saying you need to check with someone first.','Stay silent and hope it stops.',[14,20,12,16],[-12,-22,-14,-14],'A clear boundary plus distance is stronger than a long argument.'],
      ['You notice bullying in a group chat.','Do not join in, save evidence, and report through a safe channel.','Leave the chat and check on the person privately.','React publicly and make the conflict bigger.',[12,10,18,14],[-10,-12,-16,-12],'The stronger move is document, disengage, report, and support.']]
    },
    'Substances & Pressure':{icon:'🚦',intro:'Practice choices that protect health, judgment, goals, and safe friendships.',metrics:['Pressure Resistance','Health Protection','Exit Planning','Help Seeking'],scenes:[
      ['A group offers vaping or substances and says everyone is trying it.','Decline clearly and move to another activity or trusted group.','Use a short excuse and step away from the pressure.','Try it to fit in.',[18,18,16,10],[-20,-18,-20,-12],'Prepare one refusal phrase before pressure appears.'],
      ['You are worried a friend may be hiding substance use.','Speak to a trusted adult or support person rather than handling it alone.','Ask your friend to talk with a trusted support person.','Keep it secret because you promised.',[14,12,18,22],[-16,-12,-22,-20],'When safety is involved, trusted support matters more than secrecy.'],
      ['Someone says substances help with stress.','Choose safer coping support such as rest, mentoring, counselling, prayer, exercise, or journaling.','Delay the decision and choose a healthy reset first.','Use substances as stress relief.',[16,12,20,14],[-16,-14,-22,-12],'Build a stress plan before stress becomes pressure.']]
    },
    'Digital & Cyber Safety':{icon:'🔐',intro:'Practice safer decisions around passwords, scams, privacy, online conflict, and reputation.',metrics:['Cyber Awareness','Privacy Protection','Account Security','Response Action'],scenes:[
      ['A message asks you to verify your account through a strange link.','Do not click; check the account through the official app or website.','Ask a trusted person to help verify the message.','Click quickly so the account is not locked.',[18,18,20,14],[-18,-18,-22,-12],'Urgency plus a strange link is a major warning sign.'],
      ['A friend asks for your password to help with something.','Do not share it; offer another safe way to help.','Change the setting together while keeping the password private.','Share it because you trust them.',[14,20,22,12],[-14,-22,-24,-10],'A password is not a friendship test.'],
      ['An embarrassing post about you is spreading fast.','Save evidence, do not escalate, block/report, and ask for support.','Pause before responding and choose a calm support plan.','Post an angry response immediately.',[12,14,10,20],[-10,-12,-8,-18],'Respond with a plan, not emotion.']]
    },
    'Money & Gambling':{icon:'💸',intro:'Practice choices around betting, loot-style spending, scams, debt pressure, and money manipulation.',metrics:['Money Awareness','Spending Control','Scam Resistance','Future Focus'],scenes:[
      ['A betting app offers a bonus that looks like free money.','Do not sign up; review the risk and talk to a trusted adult.','Pause and read what repeated spending could cost.','Use the bonus because it feels risk-free.',[18,18,18,14],[-20,-20,-22,-14],'Free offers can be designed to pull people into repeated spending.'],
      ['A game pushes repeated paid rewards and status upgrades.','Set a spending limit and stop when the limit is reached.','Wait 24 hours before spending again.','Keep spending to catch up with others.',[12,20,10,12],[-12,-22,-8,-12],'Use limits and delay decisions.'],
      ['A friend pressures you to borrow money for a quick return.','Decline and avoid informal debt pressure.','Ask for written details and trusted advice first.','Borrow because the return sounds guaranteed.',[16,16,18,18],[-18,-18,-20,-18],'Guaranteed quick returns are warning signs.']]
    },
    'Relationships & Respect':{icon:'🤝',intro:'Practice respectful boundaries, online privacy, consent awareness, and safe relationship decisions.',metrics:['Boundary Awareness','Consent Understanding','Online Safety','Trusted Support'],scenes:[
      ['Someone asks for a private image and says it proves trust.','Refuse, protect your privacy, and ask for support if pressure continues.','Slow down and explain that trust should not require private content.','Send it because you feel pressured.',[20,18,22,18],[-24,-20,-24,-18],'Trust should not require private images or pressure.'],
      ['A relationship feels controlling and your choices are being monitored.','Recognize the warning sign and speak to a safe support person.','Write down what feels wrong and ask for perspective.','Accept it because the person says it is love.',[18,18,12,20],[-18,-18,-12,-20],'Healthy relationships include respect, safety, and freedom.'],
      ['An older person online offers gifts and asks for secrecy.','Stop the private conversation and report it to a trusted adult.','Do not share personal details and get support.','Keep chatting because the gifts feel helpful.',[20,16,20,22],[-22,-18,-22,-22],'Secrecy, gifts, and pressure from older people online are warning signs.']]
    },
    'AI & Media Truth':{icon:'🤖',intro:'Practice critical thinking around AI misinformation, deepfakes, fake profiles, and responsible use.',metrics:['AI Literacy','Critical Thinking','Responsible Use','Verification'],scenes:[
      ['An AI-generated image or video claims a major event happened today.','Verify using trusted sources before sharing.','Save it and check more than one source.','Share it quickly because it looks real.',[18,20,12,20],[-18,-22,-12,-20],'AI content can look convincing. Verify before reacting.'],
      ['You use AI to complete school work but do not understand the answer.','Use AI as a study helper and explain the work in your own words.','Ask AI to teach the steps, then check your understanding.','Submit the output as your own.',[14,18,20,12],[-12,-18,-20,-10],'AI should support learning, not replace understanding.'],
      ['A new online profile looks real but asks personal questions quickly.','Slow down, verify the identity, and avoid sharing private information.','Keep the conversation general until identity is clear.','Answer because the person seems friendly.',[16,18,14,20],[-18,-18,-12,-20],'Fake profiles can be persuasive. Protect identity and details.']]
    },
    'Education & Future':{icon:'🎓',intro:'Practice decisions that protect school progress, skills, mentorship, and future employability.',metrics:['Goal Clarity','Study Habits','Career Exposure','Mentorship'],scenes:[
      ['You are losing motivation because the future feels unclear.','Set one small weekly education or skill goal and ask for guidance.','Review one career or skill path before giving up.','Stop trying because it feels pointless.',[20,14,12,16],[-20,-16,-12,-14],'Small goals create movement when the future feels unclear.'],
      ['You are invited to skip an important class or activity.','Protect the commitment and join friends afterward.','Ask whether skipping helps or hurts your bigger goal.','Skip because you do not want to miss out.',[14,18,8,8],[-14,-20,-8,-8],'A strong future is built through repeated small choices.'],
      ['You want experience but do not know where to start.','Ask a teacher, mentor, or community contact about one entry step.','Research one volunteer, course, or job-shadow option.','Wait until someone brings an opportunity to you.',[16,12,20,20],[-14,-10,-20,-18],'Opportunity grows when you ask and follow up.']]
    }
  };
  const AGES={'10-12':'Simple choices and trusted support','13-15':'Peer pressure, identity, school, and online choices','16-18':'Independence, money, future planning, and relationships','19-24':'Work, study, finances, privacy, and adult responsibilities','25+':'Supporter, facilitator, parent, or mentor mode'};
  let selected=Object.keys(GROUPS)[0], age='13-15';
  let state={scores:[50,50,50,50],turn:0,good:0,streak:0,lastChoice:'Choose a mission and answer the first question.',lastTip:'Your readiness meter updates after each choice.',choiceSet:null};
  const clamp=n=>Math.max(0,Math.min(100,Math.round(n)));
  const avg=()=>Math.round(state.scores.reduce((a,b)=>a+b,0)/state.scores.length);
  const level=score=>score<35?'Critical':score<55?'High':score<75?'Medium':'Low';
  const cls=l=>'severity-'+String(l).toLowerCase();
  const label=m=>({'Safety Awareness':'Safety radar','Boundary Choices':'Boundaries','Trusted Support':'Trusted support','Action Readiness':'Ready action','Pressure Resistance':'Pressure check','Health Protection':'Health choices','Exit Planning':'Exit plan','Help Seeking':'Ask for help','Cyber Awareness':'Cyber radar','Privacy Protection':'Privacy','Account Security':'Account safety','Response Action':'Quick response','Money Awareness':'Money sense','Spending Control':'Spending control','Scam Resistance':'Scam radar','Future Focus':'Future focus','Boundary Awareness':'Boundaries','Consent Understanding':'Respect','Online Safety':'Online safety','AI Literacy':'AI literacy','Critical Thinking':'Think clearly','Responsible Use':'Use wisely','Verification':'Verify','Goal Clarity':'Clear goals','Study Habits':'Study habits','Career Exposure':'Career ideas','Mentorship':'Mentor help'}[m]||m);
  const guidance=s=>s<35?'Get trusted support and choose one safe next step immediately.':s<55?'Build one support action and practise the stronger choice again.':s<75?'Good progress. Strengthen one weaker power bar this week.':'Strong readiness. Keep practising and help someone else learn the safer move.';
  const scene=()=>{const g=GROUPS[selected]; const raw=g.scenes[state.turn%g.scenes.length]; return {scenario:raw[0],safe:raw[1],steady:raw[2],risk:raw[3],good:raw[4],bad:raw[5],tip:raw[6]};};
  const shuffle=a=>{a=[...a]; for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1)); [a[i],a[j]]=[a[j],a[i]];} return a;};
  function choices(s){
    if(!state.choiceSet||state.choiceSet.turn!==state.turn||state.choiceSet.group!==selected||state.choiceSet.age!==age){
      state.choiceSet={turn:state.turn,group:selected,age,items:shuffle([
        {icon:'🌟',label:'Power Move',kind:'strong',text:s.safe,effect:s.good,feedback:'Strong move — this protects your future self.'},
        {icon:'⏸️',label:'Pause Move',kind:'steady',text:s.steady,effect:[7,7,7,7],feedback:'Good pause — you slowed the situation down and reduced pressure.'},
        {icon:'⚠️',label:'Risk Move',kind:'risk',text:s.risk,effect:s.bad,feedback:'Risk spotted — this is a practice moment, not failure. Build a safer next move.'}
      ])};
    }
    return state.choiceSet.items;
  }
  function bars(g){return `<div class="lr360-game-powers">${g.metrics.map((m,i)=>{const v=state.scores[i],lv=level(v);return `<div class="lr360-game-power"><div><strong>${label(m)}</strong><span>${v}/100</span></div><div class="score-track lq-score-track"><i class="score-fill ${cls(lv)}" style="width:${v}%"></i></div><em class="impact-pill ${cls(lv)}">${lv}</em></div>`}).join('')}</div>`;}
  function categoryTiles(){return `<div class="lr360-game-category-grid">${Object.entries(GROUPS).map(([name,g])=>`<button class="lr360-game-category ${name===selected?'active':''}" data-group="${name}"><span>${g.icon}</span><strong>${name}</strong><small>${g.intro}</small></button>`).join('')}</div>`;}
  function render(){
    const g=GROUPS[selected], s=scene(), score=avg(), lv=level(score), progress=Math.min(100,Math.round((state.turn%6)/6*100));
    root.innerHTML=`<div class="lr360-game-redesign">
      <section class="lr360-game-stage">
        <div class="lr360-game-stage-copy"><span class="eyebrow">🎮 LifeQuest360 Mission Mode</span><h2>${g.icon} ${selected}</h2><p>${g.intro}</p><div class="lr360-game-badges"><span>Age: ${age}</span><span>Streak: ${state.streak}</span><span>Questions: ${state.turn}</span><span>Score: ${score}/100</span></div></div>
        <div class="lr360-game-avatar"><div class="lr360-game-ring ${cls(lv)}" style="--score:${score}"><strong>${score}</strong><span>${lv}</span></div><p>${guidance(score)}</p></div>
      </section>
      <section class="lr360-game-flow"><article><b>1</b><span>Pick Mission</span></article><article><b>2</b><span>Read Scenario</span></article><article><b>3</b><span>Choose Move</span></article><article><b>4</b><span>Level Up</span></article></section>
      <section class="lr360-game-layout">
        <aside class="game-panel lr360-game-sidebar"><h3>Mission Control</h3><label><strong>Age group</strong><select id="gameAgeGroup">${Object.keys(AGES).map(a=>`<option value="${a}" ${a===age?'selected':''}>${a} — ${AGES[a]}</option>`).join('')}</select></label>${categoryTiles()}<div class="lq-mini-progress"><span>Round progress</span><strong>${progress}%</strong><div><i style="width:${progress}%"></i></div></div></aside>
        <main class="game-panel lr360-game-card"><div class="lq-step-chip lq-step-chip-strong">Question ${state.turn+1}</div><h3>${s.scenario}</h3><p class="small">Choose the move you would make. This is practice: the aim is to learn, not to be perfect.</p><div class="lr360-game-choice-grid">${choices(s).map((c,i)=>`<button class="choice-card lr360-game-choice" data-choice="${i}"><span>${c.icon} ${c.label}</span><strong>${c.text}</strong><small>Tap to choose</small></button>`).join('')}</div></main>
        <aside class="game-panel lr360-game-results"><div class="lq-panel-heading"><div><span class="lq-step-chip">📊 Readiness</span><h3>Power Bars</h3></div><span class="impact-pill ${cls(lv)}">${lv}</span></div>${bars(g)}<div class="lr360-game-coach"><h4>Coach Feedback</h4><p><strong>Last move:</strong> ${state.lastChoice}</p><p><strong>Why it matters:</strong> ${state.lastTip}</p></div><div class="cta-row"><button class="btn dark" id="gameResetBtn">Reset</button><a class="btn primary" href="/youth-dashboard/">Open Dashboard</a></div></aside>
      </section></div>`;
    root.querySelector('#gameAgeGroup')?.addEventListener('change',e=>{age=e.target.value; reset(`Age group changed to ${age}.`);});
    root.querySelectorAll('.lr360-game-category').forEach(btn=>btn.addEventListener('click',()=>{selected=btn.dataset.group; reset(`Mission changed to ${selected}.`);}));
    root.querySelectorAll('.lr360-game-choice').forEach(btn=>btn.addEventListener('click',()=>choose(+btn.dataset.choice)));
    root.querySelector('#gameResetBtn')?.addEventListener('click',()=>reset('Game reset. Choose a mission and start again.'));
  }
  function choose(i){const c=choices(scene())[i]||choices(scene())[0]; state.scores=state.scores.map((v,x)=>clamp(v+(c.effect[x]||0))); if(c.kind==='strong'){state.good++; state.streak++;} else if(c.kind==='risk'){state.streak=0;} state.lastChoice=c.feedback; state.lastTip=scene().tip; state.turn++; state.choiceSet=null; render();}
  function reset(msg){state={scores:[50,50,50,50],turn:0,good:0,streak:0,lastChoice:msg||'Game reset.',lastTip:'Your results will update after each decision.',choiceSet:null}; render();}
  render();
}

function lr360RoleDashboardHref(role){
  const r=String(role||'').toLowerCase();
  const map={
    youth:'youth-dashboard.html',
    parent:'parent-dashboard.html',
    school:'school-dashboard.html',
    community:'community-dashboard.html',
    sponsor:'sponsor-dashboard.html',
    mitigation:'mitigation-dashboard.html',
    admin:'admin-dashboard.html'
  };
  return map[r]||'account-dashboard.html';
}
function lr360GoToRoleDashboard(user){
  const target=lr360RoleDashboardHref(user&&user.role);
  if(target){ window.location.href=target; }
}

