/* LifeRisk360 Enhanced User Bar and Youth Dashboard Load Fix */
(function(){
  const CURRENT_KEY='lr360_current_user', USERS_KEY='lr360_accounts';
  function esc(v){return String(v||'').replace(/[<>&"']/g,s=>({'<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;',"'":'&#39;'}[s]));}
  function current(){try{return JSON.parse(localStorage.getItem(CURRENT_KEY)||'null')}catch(e){return null}}
  function users(){try{return JSON.parse(localStorage.getItem(USERS_KEY)||'[]')}catch(e){return []}}
  function fmt(d){try{return new Date(d||Date.now()).toLocaleDateString(undefined,{year:'numeric',month:'short',day:'numeric'})}catch(e){return 'May 11, 2026'}}
  function roleLabel(role){return ({youth:'Youth User',parent:'Parent / Guardian',school:'School Facilitator',community:'Community Facilitator',sponsor:'Sponsor / Partner',mitigation:'Mitigation Partner',admin:'Administrator'}[role]||role||'User')}
  function accountUrl(){return (location.pathname.indexOf('/wp-')>-1 || location.pathname.indexOf('.html')===-1) ? '/account-dashboard/' : 'account-dashboard.html';}
  function logout(){try{localStorage.removeItem(CURRENT_KEY)}catch(e){} window.location.href=accountUrl();}
  window.lr360LogoutFixed=logout;
  function getStoredUser(user){return users().find(x=>(x.username||'').toLowerCase()===(user.username||'').toLowerCase())||user;}
  function barHtml(user){
    const stored=getStoredUser(user||{});
    const full=((stored.firstName||user.firstName||user.username||'User')+' '+(stored.lastName||user.lastName||'')).trim();
    const joined=fmt(stored.createdAt||user.createdAt||'2026-05-11T00:00:00.000Z');
    const initials=(full.split(/\s+/).map(x=>x[0]).join('').slice(0,2)||'LR').toUpperCase();
    return `<div class="lr360-userbar lr360-userbar-fixed" role="region" aria-label="Logged in user details"><div class="lr360-userbar-left"><div class="lr360-user-avatar" aria-hidden="true">${esc(initials)}</div><div class="lr360-user-meta"><strong>${esc(full)}</strong><span>${esc(roleLabel(stored.role||user.role))}</span><span>Joining date: ${esc(joined)}</span></div></div><div class="lr360-userbar-actions"><span class="lr360-login-status">Logged In</span><button class="btn dark lr360-userbar-logout" type="button" onclick="lr360LogoutFixed()">Log Out</button></div></div>`;
  }
  function loginPrompt(){
    return '<div class="lr360-access-required"><span class="eyebrow">Youth Login Required</span><h2>The Youth Dashboard is visible only after Youth login.</h2><p>Login with the Youth account before opening this dashboard. Parent, School, and Community users can view approved summaries from their own stakeholder dashboards.</p><div class="lr360-login-note"><strong>Test account:</strong> Youth1 / <strong>LifeRisk360</strong></div><div class="cta-row"><a class="btn primary" href="'+accountUrl()+'">Login to Account Dashboard</a></div></div>';
  }
  function protectYouthDashboard(){
    const container=document.getElementById('protectedYouthPage');
    const isYouthPage=!!container || (document.body && document.body.classList.contains('protected-youth-dashboard'));
    if(!isYouthPage) return;
    const u=current();
    if(!u || u.role!=='youth'){
      if(container && !container.dataset.locked){container.innerHTML=loginPrompt(); container.dataset.locked='true';}
      return;
    }
    if(container && container.dataset.locked==='true'){return;}
    const bar=document.getElementById('lr360YouthLoggedUserBar');
    if(bar){const html=barHtml(u); if(bar.innerHTML!==html){bar.innerHTML=html;} bar.classList.remove('lr360-userbar-placeholder');}
  }
  let applying=false;
  function apply(){
    if(applying) return; applying=true;
    try{
      protectYouthDashboard();
      const u=current();
      if(!u){applying=false;return;}
      const youth=document.getElementById('lr360YouthLoggedUserBar');
      if(youth && !youth.closest('[data-locked="true"]')){const html=barHtml(u); if(youth.innerHTML!==html) youth.innerHTML=html; youth.classList.remove('lr360-userbar-placeholder');}
      document.querySelectorAll('.lr360-session-badge').forEach(el=>{const html=barHtml(u); if(el.outerHTML!==html){el.outerHTML=html;}});
    }catch(e){console.warn('LifeRisk360 user bar update skipped',e);} finally{applying=false;}
  }
  function ready(){apply(); setTimeout(apply,250); setTimeout(apply,750); try{const obs=new MutationObserver(()=>apply()); obs.observe(document.body,{childList:true,subtree:true});}catch(e){}}
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',ready); else ready();
})();


