  function key(g,r){return (g+'--'+r).toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'')}
  function ensureVal(g,r){const k=key(g,r[0]);if(!state.values[k])state.values[k]={group:g,title:r[0],description:r[1],mitigation:r[2],likelihood:3,impact:3,awareness:55,support:55,readiness:55};return state.values[k]}
  function activeRisks(){let arr=[];state.selected.forEach(g=>(riskGroups[g]||[]).forEach(r=>arr.push(ensureVal(g,r))));if(!state.activeKey&&arr[0])state.activeKey=key(arr[0].group,arr[0].title);if(state.activeKey&&!arr.some(x=>key(x.group,x.title)===state.activeKey))state.activeKey=arr[0]?key(arr[0].group,arr[0].title):null;return arr}
