  function bindYouth(){document.querySelectorAll('.prod-risk-group').forEach(cb=>cb.addEventListener('change',()=>{state.selected=Array.from(document.querySelectorAll('.prod-risk-group:checked')).map(x=>x.value);activeRisks();renderYouth();}));const sel=document.getElementById('prodAssociatedRisk');if(sel){const rows=activeRisks();sel.innerHTML=rows.map(r=>`<option value="${esc(key(r.group,r.title))}" ${key(r.group,r.title)===state.activeKey?'selected':''}>${esc(r.group)} — ${esc(r.title)}</option>`).join('');sel.addEventListener('change',e=>{state.activeKey=e.target.value;updateSliderCard();updateYouth();});}document.getElementById('prodSaveLifePlan')?.addEventListener('click',()=>{state.life={education:val('prodLifeEducation'),career:val('prodLifeCareer'),money:val('prodLifeMoney'),digital:val('prodLifeDigital'),support:val('prodLifeSupport'),action:val('prodLifeAction')};updateYouth();});document.getElementById('prodPrint')?.addEventListener('click',()=>window.print());updateSliderCard();}
