  function updateYouth(){const rows=assessed();const meter=avg(rows,'residual');const mlev=level(meter);const ready=avg(rows,'readiness');const top=rows.slice().sort((a,b)=>b.residual-a.residual)[0];setText('prodSelectedRiskCount',rows.length);setText('prodAvgResidual',meter);setText('prodLifeReadinessText',ready+'%');const graph=document.getElementById('prodScoreGraph');if(graph)graph.innerHTML=rows.map(r=>{const pct=Math.min(100,Math.round(r.residual/25*100));return `<div class="lr360-score-row"><div class="lr360-score-label"><strong title="${esc(r.title)}">${esc(r.title)}</strong><span title="${esc(r.group)}">${esc(r.group)}</span></div><div class="lr360-score-track"><div class="lr360-score-fill ${r.level.cls}" style="width:${pct}%"></div></div><div class="lr360-score-value"><span class="lr360-prod-badge ${r.level.cls}">${r.level.label}</span><strong>${r.residual}</strong></div></div>`}).join('')||'<p>No risks selected.</p>';const heat=document.getElementById('prodHeatMap');if(heat){const counts={};rows.forEach(r=>{counts[r.likelihood+'-'+r.impact]=(counts[r.likelihood+'-'+r.impact]||0)+1});let html='';for(let impact=5;impact>=1;impact--){for(let likelihood=1;likelihood<=5;likelihood++){const sc=likelihood*impact,lv=level(sc),ct=counts[likelihood+'-'+impact]||0;html+=`<div class="lr360-heat-cell ${lv.cls} ${ct?'active':''}"><span>${sc}</span>${ct?`<b>${ct}</b>`:''}</div>`}}heat.innerHTML=html;}const reg=document.getElementById('prodRiskRegister');if(reg)reg.innerHTML=rows.map(r=>`<tr><td>${esc(r.group)}</td><td>${esc(r.title)}</td><td>${r.likelihood}</td><td>${r.impact}</td><td>${r.raw}</td><td>${r.residual}</td><td><span class="lr360-prod-badge ${r.level.cls}">${r.level.label}</span></td><td>${esc(r.mitigation)}</td></tr>`).join('')||'<tr><td colspan="8">Select risk groups to build the risk register.</td></tr>';const sum=document.getElementById('prodSliderSummary');if(sum){const avgL=avg(rows,'likelihood'),avgI=avg(rows,'impact'),avgCtrl=rows.length?Math.round(rows.reduce((a,r)=>a+(r.awareness+r.support+r.readiness)/3,0)/rows.length):0;sum.innerHTML=`<div class="lr360-prod-metric"><span>Avg Likelihood</span><strong>${avgL}</strong><small>1 to 5</small></div><div class="lr360-prod-metric"><span>Avg Impact</span><strong>${avgI}</strong><small>1 to 5</small></div><div class="lr360-prod-metric"><span>Avg Control Strength</span><strong>${avgCtrl}%</strong><small>awareness, support, readiness</small></div>`}const out=document.getElementById('prodLifeOutput');if(out){out.innerHTML=`<p><strong>Life Direction Statement:</strong> I will protect my future by reducing ${top?esc(top.title):'priority risks'}, strengthening my support circle, and taking practical weekly steps toward school, digital safety, money readiness, and career preparation.</p><ul><li><strong>Education:</strong> ${esc(val('prodLifeEducation')||'Set a clear education milestone.')}</li><li><strong>Career / Skills:</strong> ${esc(val('prodLifeCareer')||'Choose one skill pathway.')}</li><li><strong>Economic Readiness:</strong> ${esc(val('prodLifeMoney')||'Build a simple budget habit.')}</li><li><strong>Digital Responsibility:</strong> ${esc(val('prodLifeDigital')||'Protect accounts and online reputation.')}</li><li><strong>Support Circle:</strong> ${esc(val('prodLifeSupport')||'Identify trusted support people.')}</li><li><strong>Next 7 Days:</strong> ${esc(val('prodLifeAction')||'Complete the first remediation step.')}</li></ul>`}const rem=document.getElementById('prodRemediation');if(rem){rem.innerHTML=rows.slice().sort((a,b)=>b.residual-a.residual).slice(0,5).map((r,i)=>`<div class="lr360-remediation-item"><span>${i+1}</span><div><strong>${esc(r.title)} <em class="lr360-prod-badge ${r.level.cls}">${r.level.label}</em></strong><p>${esc(r.mitigation)}</p></div></div>`).join('')||'<p>Select risks to generate remediation steps.</p>'}localStorage.setItem(PSC_KEY,JSON.stringify({lastUpdated:new Date().toISOString(),youth:'Youth1',consentStatus:'Approved sample access',ageGroup:state.ageGroup||'13-15',ageLabel:youthAge().label,groups:state.selected,riskMeter:meter,impactLevel:mlev.label,readiness:ready,topRisks:rows.slice().sort((a,b)=>b.residual-a.residual).slice(0,5).map(r=>({category:r.group,title:r.title,residual:r.residual,level:r.level.label,mitigation:r.mitigation})),register:rows.map(r=>({category:r.group,title:r.title,likelihood:r.likelihood,impact:r.impact,residual:r.residual,level:r.level.label}))}));}
