  function initials(u){const name=((u?.firstName||u?.username||'Y')+' '+(u?.lastName||'')).trim();return name.split(/\s+/).map(x=>x[0]).join('').slice(0,2).toUpperCase()||'YD'}
  function userbar(u){const nm=((u.firstName||u.username||'Youth')+' '+(u.lastName||'')).trim(); return `<div class="lr360-vibe-userbar"><div class="lr360-vibe-user-right"><div class="lr360-vibe-avatar">${esc(initials(u))}</div><div class="lr360-vibe-usertext"><strong>${esc(nm)}</strong><span>${esc(roles[u.role]||u.role)}</span><span>Joining date: ${esc(joined(u))}</span></div><span class="lr360-vibe-badge">Logged In</span><button class="btn dark" type="button" onclick="localStorage.removeItem('lr360_current_user'); location.href='/account-dashboard/'">Log Out</button></div></div>`; }
  function key(group,title){return (group+'__'+title).toLowerCase().replace(/[^a-z0-9]+/g,'-');}
  function ensureValues(){let first=null; state.selected.forEach(group=>{(GROUPS[group]?.risks||[]).forEach(item=>{const [title,desc,rem]=item; const k=key(group,title); if(!first) first=k; if(!state.values[k]) state.values[k]={key:k,group,title,description:desc,remediation:rem,likelihood:3,impact:3,awareness:55,support:50,readiness:50};});}); if(!state.active || !state.values[state.active]) state.active=first; }
  function activeRisks(){ensureValues(); let arr=[]; state.selected.forEach(group=>{(GROUPS[group]?.risks||[]).forEach(item=>{const k=key(group,item[0]); if(state.values[k]) arr.push(state.values[k]);});}); return arr; }
  function riskMetrics(r){ const chance=r.likelihood/5, impact=r.impact/5, controlGap=((100-r.awareness)+(100-r.support)+(100-r.readiness))/300; const residual=Math.round((chance*0.35 + impact*0.35 + controlGap*0.30)*100); const readiness=Math.round((r.awareness+r.support+r.readiness)/3); const raw=r.likelihood*r.impact; const level=zone(residual); return {...r, residual, readiness, raw, level}; }
