  function loginPrompt(){ return `<div class="lr360-access-required"><span class="eyebrow">Login Required</span><h2>The Youth Dashboard is visible only after login.</h2><p>Use the LifeRisk360 youth test account to open your private dashboard.</p><div class="lr360-login-note"><strong>Test account:</strong> Youth1 &nbsp; <strong>Password:</strong> LifeRisk360</div><div class="cta-row"><a class="btn primary" href="/account-dashboard/">Login to continue</a></div></div>`; }
