  function focusCards(){ return state.selected.map(x=>x); }
  function groupCards(){ return Object.keys(GROUPS).map((g)=>{const on=state.selected.includes(g);const count=(GROUPS[g].risks||[]).length;return `<label class="lr360-focus-check ${on?'is-selected':''} ${GROUPS[g].color}" title="${esc(count+' risks in '+friendlyGroup(g))}"><span class="lr360-check-control"><input type="checkbox" class="lr360-vibe-group" value="${esc(g)}" ${on?'checked':''}><span class="fake-box" aria-hidden="true"></span></span><span class="emoji" aria-hidden="true">${GROUPS[g].icon}</span><span class="focus-copy"><span class="label">${esc(friendlyGroup(g))}</span><span class="risk-count">${count} risks</span></span><span class="pick">${on?'Selected':'Select'}</span></label>`}).join(''); }
