  function sliderRow(r, field, label, hint, min, max){ const val=r[field]; return `<div class="lr360-vibe-slider"><div class="lr360-vibe-slider-head"><label for="${field}-${r.key}">${label}</label><strong id="${field}-${r.key}-out">${val}${max===100?'%':''}</strong></div><small>${hint}</small><input id="${field}-${r.key}" type="range" min="${min}" max="${max}" value="${val}" data-key="${r.key}" data-field="${field}"><div class="lr360-vibe-slider-scale"><span>${min===1?'Low':'Needs work'}</span><span>${max===5?'High':'Strong'}</span></div></div>`; }
  function activeRiskCard(rows){ const r=rows.find(x=>x.key===state.active) || rows[0]; if(!r) return `<div class="callout"><p>Select one or more focus areas to unlock your interactive risk explorer.</p></div>`; state.active=r.key; const z=r.level; return `<div class="lr360-vibe-risk-card ${z.cls}"><div class="lr360-vibe-risk-top"><div><span class="eyebrow">${GROUPS[r.group]?.icon||'⭐'} ${esc(friendlyGroup(r.group))}</span><h3><span class="heading-icon">⚡</span>${esc(r.title)}</h3><p>${esc(r.description)}</p></div><div class="lr360-vibe-zone ${z.cls}">${z.emoji} ${z.label}</div></div><div class="lr360-vibe-micro-metrics"><div><span>📡 Risk level</span><strong>${r.residual}/100</strong></div><div><span>🛡️ Readiness</span><strong>${r.readiness}%</strong></div><div><span>⚖️ Likelihood × Impact</span><strong>${r.raw}/25</strong></div></div><div class="lr360-vibe-slider-grid">${sliderRow(r,'likelihood','How likely is this?','How likely is this to affect you right now?',1,5)}${sliderRow(r,'impact','How big is the impact?','If it happens, how much could it affect your life?',1,5)}${sliderRow(r,'awareness','How aware are you?','How well do you understand this risk?',0,100)}${sliderRow(r,'support','How much support do you have?','Do you have people who can help you with this?',0,100)}${sliderRow(r,'readiness','How ready are you?','How ready are you to make a safer move?',0,100)}</div><div class="lr360-vibe-next-step"><strong>✅ Next step:</strong> ${esc(r.remediation)}</div></div>`; }
  function summary(rows){ const high=rows.filter(r=>r.level.label==='High'||r.level.label==='Critical').length; const ready=avg(rows,'readiness'); const m=meterData(rows); return `<section class="lr360-vibe-summary"><div class="metric icon-metric"><b class="tile-icon">🧭</b><span>Focus Areas</span><strong>${state.selected.length}</strong><small>selected</small></div><div class="metric icon-metric"><b class="tile-icon">🎚️</b><span>Risks Rated</span><strong>${rows.length}</strong><small>interactive sliders</small></div><div class="metric icon-metric"><b class="tile-icon">🚀</b><span>Life Readiness</span><strong>${ready}%</strong><small>${ready>=70?'great progress':ready>=45?'building up':'needs support'}</small></div><div class="metric icon-metric"><b class="tile-icon">🔥</b><span>High Priorities</span><strong>${high}</strong><small>areas to work on</small></div><div class="lr360-vibe-meter-tile ${m.z.cls}"><div class="dial" style="--meter:${m.pct}"><div><strong>${m.score}</strong><span>/100</span></div></div><div class="copy"><span><i>📡</i> Your Risk Meter</span><strong>${m.z.label}</strong><small>${m.z.note}</small></div></div></section>`; }
