  function persistPSC(rows){ const m=meterData(rows), ready=avg(rows,'readiness'); const payload={lastUpdated:new Date().toISOString(), youth:'Youth1', consentStatus:'Approved sample access', groups:state.selected.slice(), riskMeter:m.score, impactLevel:m.z.label, readiness:ready, topRisks:rows.slice().sort((a,b)=>b.residual-a.residual).slice(0,5).map(r=>({category:r.group,title:r.title,residual:r.residual,level:r.level.label,mitigation:r.remediation})), lifePlan:{future:state.plan.future||'',bigGoal:state.plan.bigGoal||'',yearGoal:state.plan.yearGoal||'',action:state.plan.action||'',checkIn:state.plan.checkIn||'',support:state.plan.support||''}, register:rows.map(r=>({category:r.group,title:r.title,likelihood:r.likelihood,impact:r.impact,residual:r.residual,level:r.level.label}))}; localStorage.setItem(PSC_KEY, JSON.stringify(payload)); }
